import * as React from 'react'
import { experimentalStyled as styled } from '@mui/material/styles'
import Box from '@mui/material/Box'
import Paper from '@mui/material/Paper'
import Grid from '@mui/material/Grid'
import om from './assets/om.png'

const Item = styled(Paper)(({ theme }) => ({
  backgroundColor: theme.palette.mode === 'dark' ? '#1A2027' : '#fff',
  ...theme.typography.body2,
  padding: theme.spacing(2),
  textAlign: 'center',
  color: theme.palette.text.secondary,
}))

export default function ResponsiveGrid() {
  const projectlist = [
    {
      name: 'Opinion Maximization',
      description: 'Aims at maximizing opinion in signed social networks',
    },
    {
      name: 'Pen Ink differentation in hand -written documents',
      description: 'Detecting fraud in bank checks',
    },
    {
      name: 'Understanding Preferential attachment in play games games network',
      description: 'Aims at maximizing opinion in signed social networks',
    },
    {
      name: 'Vehicle Collision and Alchohol detection System',
      description: 'Aims at maximizing opinion in signed social networks',
    },
    {
      name: 'Traffic Management and Monitoring',
      description: 'Aims at maximizing opinion in signed social networks',
    },
    {
      name: 'Web Application for automated gate management',
      description: 'Aims at maximizing opinion in signed social networks',
    },
  ]
  return (
    <Box sx={{ flexGrow: 1 }}>
      <Grid
        container
        spacing={{ xs: 2, md: 3 }}
        columns={{ xs: 4, sm: 8, md: 12 }}
      >
        {projectlist.map((i, index) => (
          <Grid item xs={2} sm={4} md={4} key={index}>
            <Item>project</Item>
            <div style={{ backgroundColor: 'white' }}>{i.name}</div>
            <div style={{ backgroundColor: 'white' }}>{i.description}</div>
          </Grid>
        ))}
      </Grid>
    </Box>
  )
}
